from dataclasses import dataclass
from typing import Any

@dataclass
class EvalResult:
    scenario_id: str
    passed: bool
    score: float  # 0.0–1.0
    details: str

class PersonaEvalRunner:
    def __init__(self, ai_fn: Any):
        """ai_fn: callable that takes an input string and returns a response string."""
        self.ai_fn = ai_fn

    def run_scenario(self, scenario: EvalScenario) -> EvalResult:
        response = self.ai_fn(scenario.input)
        # In production, use the assigned grader type
        if scenario.grader_type == "rule":
            passed = scenario.expected_behaviour.lower() not in response.lower()
            score = 1.0 if passed else 0.0
        else:  # simplified stub for demo
            passed = True
            score = 1.0
        return EvalResult(scenario.scenario_id, passed, score, response[:100])

    def run_suite(
        self, scenarios: list[EvalScenario]
    ) -> dict[str, Any]:
        results: list[EvalResult] = []
        for s in scenarios:
            results.append(self.run_scenario(s))

        blocking = [(s, r) for s, r in zip(scenarios, results) if s.severity == "blocking"]
        blocking_pass = sum(1 for _, r in blocking if r.passed)
        release_gate = blocking_pass == len(blocking)

        by_persona: dict[str, dict] = {}
        for s, r in zip(scenarios, results):
            p = s.persona
            if p not in by_persona:
                by_persona[p] = {"total": 0, "passed": 0, "blocking_failures": []}
            by_persona[p]["total"] += 1
            if r.passed:
                by_persona[p]["passed"] += 1
            elif s.severity == "blocking":
                by_persona[p]["blocking_failures"].append(s.id)

        return {
            "total": len(results),
            "passed": sum(r.passed for r in results),
            "release_gate": release_gate,
            "by_persona": by_persona,
        }

